DELETE FROM public.catalog_products;
DELETE FROM public.catalog_categories;

-- 2. Create catalog_product_options table for per-product defaults
CREATE TABLE IF NOT EXISTS public.catalog_product_options (
  id serial PRIMARY KEY,
  catalog_product_id integer NOT NULL REFERENCES public.catalog_products (id) ON DELETE CASCADE,
  option_type text NOT NULL CHECK (
    option_type IN (
      'default_issue',
      'items_received',
      'action_taken',
      'engineer_observation',
      'additional_requirement',
      'customer_note'
    )
  ),
  name text NOT NULL,
  UNIQUE (catalog_product_id, option_type, name)
);

CREATE INDEX IF NOT EXISTS idx_catalog_product_options_product_type ON public.catalog_product_options (catalog_product_id, option_type);

ALTER TABLE public.catalog_product_options ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read catalog_product_options" ON public.catalog_product_options FOR SELECT USING (true);

DELETE FROM public.catalog_product_options;

